import { useState } from 'react';
import './App.css';
import Header from './components/header/header';
import ResultsGrid from './components/resultsgrid/resultsgrid'
import Result from './components/result/result';
import Fixture from './components/data/fixtures';

function App() {

  // create some state with no default (useState() is empty)
  // pass the setfixture function through as a ref to the grid. This is then passed through to the row element for onclick. 
  // if current view is not null then we render that result (if something has been clicked) - otherwise we show the list.
  const [currentView, setFixture] = useState();

  const setFixtureWrapper = (Fixture : any) => 
  {
      // Here we could do some checks i.e. check fixture is actually a fixture or validate it.
      setFixture(Fixture);
  }


  return (
    <>
      <Header/>
      {currentView ? <Result fixture={currentView} /> :  <ResultsGrid viewFixture={setFixtureWrapper}/>}
    </>
  );
}

export default App;
